const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Array<{ op: "quote"; items: Array<{ type: string }> }>;
};

type QuoteResult = { premium: number };

const quotePremium = (items: Array<{ type: string }>): QuoteResult => {
  if (items.length === 0) return { premium: PROCESSING_FEE };
  const base = BASE_PREMIUMS[items[0].type];
  const firstInsurance = base * FIRST_INSURANCE_RATE;
  return { premium: base + firstInsurance + PROCESSING_FEE };
};

export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
  const results = scenario.steps.map((step) => quotePremium(step.items));
  return { results };
};
